#include <iostream>

using namespace std;

int factorial(int n)
{
    if (n == 0) // BASE CASE
    {
        return 1;
    }
    return n * factorial(n - 1); // RECURSIVE CASE
}

int main()
{
    cout << factorial(4) << endl;

    return 0;
}

int broken(int n)
{
    return n * broken(n - 1); // no base case — NEVER stops calling itself
}

